import { Loader } from "lucide-react";
import { Fragment, type ReactNode } from "react";

import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";

export const SubmitButton = ({
  isSubmitting,
  disabled,
  text,
  loadingText,
  icon,
  className,
  onClick,
}: {
  isSubmitting?: boolean;
  disabled?: boolean;
  text?: string;
  loadingText?: string;
  icon?: ReactNode;
  className?: string;
  onClick?: () => void;
}) => {
  text = text ?? "Save";
  loadingText = loadingText ?? "Saving...";
  return (
    <Button
      type="submit"
      className={cn("cursor-pointer select-none", className)}
      disabled={isSubmitting || disabled}
      onClick={onClick}
    >
      {isSubmitting ? (
        <Fragment>
          <Loader className="animate-spin" />
          <span>{loadingText}</span>
        </Fragment>
      ) : (
        <Fragment>
          {icon && <span className="mr-1">{icon}</span>}
          <span>{text}</span>
        </Fragment>
      )}
    </Button>
  );
};

import { CircleAlertIcon } from "lucide-react";

import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import { ScrollArea } from "@/components/ui/scroll-area";

import type { StandardSchemaV1Issue } from "@tanstack/react-form";

export type FormError = Record<string, StandardSchemaV1Issue[]> | undefined;

export const FormErrors = ({ errors }: { errors: FormError[] }) => {
  const validErrors = errors.filter(
    (error): error is Record<string, StandardSchemaV1Issue[]> =>
      error !== undefined && error !== null && Object.keys(error).length > 0,
  );

  if (validErrors.length === 0) {
    return null;
  }

  return (
    <Dialog>
      <DialogTrigger asChild>
        <Button
          variant="destructive"
          size="icon-sm"
          className="cursor-pointer"
        >
          <CircleAlertIcon />
        </Button>
      </DialogTrigger>
      <DialogContent className="sm:max-w-md">
        <DialogHeader>
          <DialogTitle>Form Errors</DialogTitle>
          <DialogDescription>
            The form contains the following errors:
          </DialogDescription>
        </DialogHeader>
        <ScrollArea className="max-h-[300px]">
          <div className="space-y-4 pr-4">
            {validErrors.map((errorRecord) => {
              const recordKey = Object.keys(errorRecord).sort().join("-");
              return (
                <div
                  key={recordKey}
                  className="space-y-2"
                >
                  {Object.entries(errorRecord).map(([field, issues]) => (
                    <div
                      key={field}
                      className="space-y-1"
                    >
                      <p className="text-sm font-medium capitalize">
                        {field.replace(/_/g, " ")}
                      </p>
                      <ul className="text-destructive list-disc space-y-1 pl-4 text-sm">
                        {issues.map((issue) => (
                          <li
                            key={`${field}-${issue.path?.join(".") ?? ""}-${issue.message}`}
                          >
                            {issue.message}
                          </li>
                        ))}
                      </ul>
                    </div>
                  ))}
                </div>
              );
            })}
          </div>
        </ScrollArea>
      </DialogContent>
    </Dialog>
  );
};

import { useForm } from "@tanstack/react-form";

import { AlertError, Loading } from "@/components/fsui/fscommon";

import { SubmitButton } from "./button";

import type {
  FormAsyncValidateOrFn,
  FormValidateOrFn,
  ReactFormExtendedApi,
} from "@tanstack/react-form";
import type { ReactNode, RefObject } from "react";
import type * as z from "zod";

export * from "./button";

export type FormSubmitter =
  | {
      text: string;
      loadingText?: string;
    }
  | ((props: { isSubmitting: boolean; canSubmit: boolean }) => ReactNode);

export type UseFormReturnOnSubmitType<T extends z.ZodObject = z.ZodObject> =
  ReactFormExtendedApi<
    z.input<T>, // TFormData
    FormValidateOrFn<z.input<T>> | undefined, // TOnMount
    FormValidateOrFn<z.input<T>> | undefined, // TOnChange
    FormAsyncValidateOrFn<z.input<T>> | undefined, // TOnChangeAsync
    FormValidateOrFn<z.input<T>> | undefined, // TOnBlur
    FormAsyncValidateOrFn<z.input<T>> | undefined, // TOnBlurAsync
    T, // TOnSubmit
    FormAsyncValidateOrFn<z.input<T>> | undefined, // TOnSubmitAsync
    FormValidateOrFn<z.input<T>> | undefined, // TOnDynamic
    FormAsyncValidateOrFn<z.input<T>> | undefined, // TOnDynamicAsync
    FormAsyncValidateOrFn<z.input<T>> | undefined, // TOnServer
    unknown // TSubmitMeta
  >;

export type UseFormReturnOnChangeType<T extends z.ZodObject = z.ZodObject> =
  ReactFormExtendedApi<
    z.input<T>, // TFormData
    FormValidateOrFn<z.input<T>> | undefined, // TOnMount
    T, // TOnChange
    FormAsyncValidateOrFn<z.input<T>> | undefined, // TOnChangeAsync
    FormValidateOrFn<z.input<T>> | undefined, // TOnBlur
    FormAsyncValidateOrFn<z.input<T>> | undefined, // TOnBlurAsync
    FormValidateOrFn<z.input<T>> | undefined, // TOnSubmit
    FormAsyncValidateOrFn<z.input<T>> | undefined, // TOnSubmitAsync
    FormValidateOrFn<z.input<T>> | undefined, // TOnDynamic
    FormAsyncValidateOrFn<z.input<T>> | undefined, // TOnDynamicAsync
    FormAsyncValidateOrFn<z.input<T>> | undefined, // TOnServer
    unknown // TSubmitMeta
  >;

export type FieldApiOnChangeType<T extends z.ZodObject = z.ZodObject> =
  Parameters<
    Parameters<UseFormReturnOnChangeType<T>["Field"]>[0]["children"]
  >[0];

export type FieldApiOnSubmitType<T extends z.ZodObject = z.ZodObject> =
  Parameters<
    Parameters<UseFormReturnOnSubmitType<T>["Field"]>[0]["children"]
  >[0];

// export type UseFormReturnType<T extends z.ZodObject> = ReactFormExtendedApi<
//   z.input<T>,
//   FormValidateOrFn<z.input<T>> | undefined,
//   FormValidateOrFn<z.input<T>> | undefined,
//   FormAsyncValidateOrFn<z.input<T>> | undefined,
//   FormValidateOrFn<z.input<T>> | undefined,
//   FormAsyncValidateOrFn<z.input<T>> | undefined,
//   FormValidateOrFn<z.input<T>> | undefined,
//   FormAsyncValidateOrFn<z.input<T>> | undefined,
//   FormValidateOrFn<z.input<T>> | undefined,
//   FormAsyncValidateOrFn<z.input<T>> | undefined,
//   FormAsyncValidateOrFn<z.input<T>> | undefined,
//   unknown
// >;

export type ValidationMethod = "onChange" | "onSubmit";
export type SubmitFormPropsBase<T extends z.ZodObject> = {
  formSchema: T;
  validationMethod: ValidationMethod;
  error?: Error | null;
  isLoading?: boolean;
  className?: string;
  submitter?: FormSubmitter;
  defaultValues?: z.input<T>;
  manualSubmitter?: boolean;
  children?: ReactNode;
  ref?: RefObject<HTMLFormElement | null>;
  onSubmit: (props: { value: z.input<T> }) => Promise<void> | void;
};

export type SubmitFormPropsOnChange<T extends z.ZodObject> =
  SubmitFormPropsBase<T> & {
    validationMethod: "onChange";
    render?: (form: UseFormReturnOnChangeType<T>) => ReactNode;
  };

export type SubmitFormPropsOnSubmit<T extends z.ZodObject> =
  SubmitFormPropsBase<T> & {
    validationMethod: "onSubmit";
    render?: (form: UseFormReturnOnSubmitType<T>) => ReactNode;
  };

export type SubmitFormProps<T extends z.ZodObject> =
  | SubmitFormPropsOnChange<T>
  | SubmitFormPropsOnSubmit<T>;

export const SubmitForm = <T extends z.ZodObject>(
  props: SubmitFormProps<T>,
) => {
  const {
    formSchema,
    validationMethod = "onChange",
    defaultValues,
    children,
    manualSubmitter,
    error,
    isLoading,
    className,
    ref,
    onSubmit,
  } = props;

  let { submitter } = props;

  if (!submitter) {
    submitter = SubmitButton;
  }

  const form = useForm({
    onSubmit,
    defaultValues,
    validators: {
      // onSubmit: formSchema,
      // onChange: formSchema,
      [validationMethod]: formSchema,
    },
  }) as UseFormReturnOnSubmitType<T> & UseFormReturnOnChangeType<T>;

  if (error) {
    return <AlertError error={error} />;
  }

  if (isLoading) {
    return <Loading />;
  }

  return (
    <form
      ref={ref}
      className={className}
      onSubmit={(e) => {
        e.preventDefault();
        form.handleSubmit();
      }}
    >
      {props.render?.(form)}
      {!manualSubmitter && (
        <div className="mt-4 flex justify-center">
          <form.Subscribe
            selector={(state) => [state.canSubmit, state.isSubmitting]}
            children={([canSubmit, isSubmitting]) =>
              "text" in submitter ? (
                <SubmitButton
                  className="w-full"
                  disabled={canSubmit}
                  isSubmitting={isSubmitting}
                  text={submitter.text}
                  loadingText={submitter.loadingText ?? submitter.text}
                />
              ) : (
                submitter({ canSubmit, isSubmitting })
              )
            }
          />
        </div>
      )}
      {children}
    </form>
  );
};
